    "content": "{"content":"// SPDX-License-Identifier: GPL-2.0\n/*\n * Copyright (C) 2010 Kent Overstreet <kent.overstreet@gmail.com>\n *\n * Uses a block device as cache for other block devices; optimized for SSDs.\n * All allocation is done in buckets, which should match the erase block size\n * of the device.\n *\n * Buckets containing cached data are kept on a heap sorted by priority;\n * bucket priority is increased on cache hit, and periodically all the buckets\n * on the heap have their priority scaled down. This currently is just used as\n * an LRU but in the future should allow for more intelligent heuristics.\n *\n * Buckets have an 8 bit counter; freeing is accomplished by incrementing the\n * counter. Garbage collection is used to remove stale pointers.\n *\n * Indexing is done via a btree; nodes are not necessarily fully sorted, rather\n * as keys are inserted we only sort the pages that have not yet been written.\n * When garbage collection is run, we resort the entire node.\n *\n * All configuration is done via sysfs; see Documentation/admin-guide/bcache.rst.\n */\n\n#include \"bcache.h\"\n#include \"btree.h\"\n#include \"debug.h\"\n#include \"extents.h\"\n\n#include <linux/slab.h>\n#include <linux/bitops.h>\n#include <linux/hash.h>\n#include <linux/kthread.h>\n#include <linux/prefetch.h>\n#include <linux/random.h>\n#include <linux/rcupdate.h>\n#include <linux/sched/clock.h>\n#include <linux/rculist.h>\n#include <linux/delay.h>\n#include <linux/sort.h>\n#include <trace/events/bcache.h>\n\n/*\n * Todo:\n * register_bcache: Return errors out to userspace correctly\n *\n * Writeback: don't undirty key until after a cache flush\n *\n * Create an iterator for key pointers\n *\n * On btree write error, mark bucket such that it won't be freed from the cache\n *\n * Journalling:\n *   Check for bad keys in replay\n *   Propagate barriers\n *   Refcount journal entries in journal_replay\n *\n * Garbage collection:\n *   Finish incremental gc\n *   Gc should free old UUIDs, data for invalid UUIDs\n *\n * Provide a way to list backing device UUIDs we have data cached for, and\n * probably how long it's been since we've seen them, and a way to invalidate\n * dirty data for devices that will never be attached again\n *\n * Keep 1 min/5 min/15 min statistics of how busy a block device has been, so\n * that based on that and how much dirty data we have we can keep writeback\n * from being starved\n *\n * Add a tracepoint or somesuch to watch for writeback starvation\n *\n * When btree depth > 1 and splitting an interior node, we have to make sure\n * alloc_bucket() cannot fail. This should be true but is not completely\n * obvious.\n *\n * Plugging?\n *\n * If data write is less than hard sector size of ssd, round up offset in open\n * bucket to the next whole sector\n *\n * Superblock needs to be fleshed out for multiple cache devices\n *\n * Add a sysfs tunable for the number of writeback IOs in flight\n *\n * Add a sysfs tunable for the number of open data buckets\n *\n * IO tracking: Can we track when one process is doing io on behalf of another?\n * IO tracking: Don't use just an average, weigh more recent stuff higher\n *\n * Test module load/unload\n */\n\n#define MAX_GC_TIMES_SHIFT\t7  /* 128 loops */\n#define GC_NODES_MIN\t\t10\n#define GC_SLEEP_MS_MIN\t\t10\n#define GC_SLEEP_MS\t\t100\n\n#define PTR_DIRTY_BIT\t\t(((uint64_t) 1 << 36))\n\n#define PTR_HASH(c, k)\t\t\t\t\t\t\t\\\n\t(((k)->ptr[0] >> c->bucket_bits) | PTR_GEN(k, 0))\n\nstatic struct workqueue_struct *btree_io_wq;\n\n#define insert_lock(s, b)\t((b)->level <= (s)->lock)\n\n\nstatic inline struct bset *write_block(struct btree *b)\n{\n\treturn ((void *) btree_bset_first(b)) + b->written * block_bytes(b->c->cache);\n}\n\nstatic void bch_btree_init_next(struct btree *b)\n{\n\t/* If not a leaf node, always sort */\n\tif (b->level && b->keys.nsets)\n\t\tbch_btree_sort(&b->keys, &b->c->sort);\n\telse\n\t\tbch_btree_sort_lazy(&b->keys, &b->c->sort);\n\n\tif (b->written < btree_blocks(b))\n\t\tbch_bset_init_next(&b->keys, write_block(b),\n\t\t\t\t   bset_magic(&b->c->cache->sb));\n\n}\n\n/* Btree key manipulation */\n\nvoid bkey_put(struct cache_set *c, struct bkey *k)\n{\n\tunsigned int i;\n\n\tfor (i = 0; i < KEY_PTRS(k); i++)\n\t\tif (ptr_available(c, k, i))\n\t\t\tatomic_dec_bug(&PTR_BUCKET(c, k, i)->pin);\n}\n\n/* Btree IO */\n\nstatic uint64_t btree_csum_set(struct btree *b, struct bset *i)\n{\n\tuint64_t crc = b->key.ptr[0];\n\tvoid *data = (void *) i + 8, *end = bset_bkey_last(i);\n\n\tcrc = crc64_be(crc, data, end - data);\n\treturn crc ^ 0xffffffffffffffffULL;\n}\n\nvoid bch_btree_node_read_done(struct btree *b)\n{\n\tconst char *err = \"bad btree header\";\n\tstruct bset *i = btree_bset_first(b);\n\tstruct btree_iter *iter;\n\n\t/*\n\t * c->fill_iter can allocate an iterator with more memory space\n\t * than static MAX_BSETS.\n\t * See the comment arount cache_set->fill_iter.\n\t */\n\titer = mempool_alloc(&b->c->fill_iter, GFP_NOIO);\n\titer->size = b->c->cache->sb.bucket_size / b->c->cache->sb.block_size;\n\titer->used = 0;\n\n#ifdef CONFIG_BCACHE_DEBUG\n\titer->b = &b->keys;\n#endif\n\n\tif (!i->seq)\n\t\tgoto err;\n\n\tfor (;\n\t     b->written < btree_blocks(b) && i->seq == b->keys.set[0].data->seq;\n\t     i = write_block(b)) {\n\t\terr = \"unsupported bset version\";\n\t\tif (i->version > BCACHE_BSET_VERSION)\n\t\t\tgoto err;\n\n\t\terr = \"bad btree header\";\n\t\tif (b->written + set_blocks(i, block_bytes(b->c->cache)) >\n\t\t    btree_blocks(b))\n\t\t\tgoto err;\n\n\t\terr = \"bad magic\";\n\t\tif (i->magic != bset_magic(&b->c->cache->sb))\n\t\t\tgoto err;\n\n\t\terr = \"bad checksum\";\n\t\tswitch (i->version) {\n\t\tcase 0:\n\t\t\tif (i->csum != csum_set(i))\n\t\t\t\tgoto err;\n\t\t\tbreak;\n\t\tcase BCACHE_BSET_VERSION:\n\t\t\tif (i->csum != btree_csum_set(b, i))\n\t\t\t\tgoto err;\n\t\t\tbreak;\n\t\t}\n\n\t\terr = \"empty set\";\n\t\tif (i != b->keys.set[0].data && !i->keys)\n\t\t\tgoto err;\n\n\t\tbch_btree_iter_push(iter, i->start, bset_bkey_last(i));\n\n\t\tb->written += set_blocks(i, block_bytes(b->c->cache));\n\t}\n\n\terr = \"corrupted btree\";\n\tfor (i = write_block(b);\n\t     bset_sector_offset(&b->keys, i) < KEY_SIZE(&b->key);\n\t     i = ((void *) i) + block_bytes(b->c->cache))\n\t\tif (i->seq == b->keys.set[0].data->seq)\n\t\t\tgoto err;\n\n\tbch_btree_sort_and_fix_extents(&b->keys, iter, &b->c->sort);\n\n\ti = b->keys.set[0].data;\n\terr = \"short btree key\";\n\tif (b->keys.set[0].size &&\n\t    bkey_cmp(&b->key, &b->keys.set[0].end) < 0)\n\t\tgoto err;\n\n\tif (b->written < btree_blocks(b))\n\t\tbch_bset_init_next(&b->keys, write_block(b),\n\t\t\t\t   bset_magic(&b->c->cache->sb));\nout:\n\tmempool_free(iter, &b->c->fill_iter);\n\treturn;\nerr:\n\tset_btree_node_io_error(b);\n\tbch_cache_set_error(b->c, \"%s at bucket %zu, block %u, %u keys\",\n\t\t\t    err, PTR_BUCKET_NR(b->c, &b->key, 0),\n\t\t\t    bset_block_offset(b, i), i->keys);\n\tgoto out;\n}\n\nstatic void btree_node_read_endio(struct bio *bio)\n{\n\tstruct closure *cl = bio->bi_private;\n\n\tclosure_put(cl);\n}\n\nstatic void bch_btree_node_read(struct btree *b)\n{\n\tuint64_t start_time = local_clock();\n\tstruct closure cl;\n\tstruct bio *bio;\n\n\ttrace_bcache_btree_read(b);\n\n\tclosure_init_stack(&cl);\n\n\tbio = bch_bbio_alloc(b->c);\n\tbio->bi_iter.bi_size = KEY_SIZE(&b->key) << 9;\n\tbio->bi_end_io\t= btree_node_read_endio;\n\tbio->bi_private\t= &cl;\n\tbio->bi_opf = REQ_OP_READ | REQ_META;\n\n\tbch_bio_map(bio, b->keys.set[0].data);\n\n\tbch_submit_bbio(bio, b->c, &b->key, 0);\n\tclosure_sync(&cl);\n\n\tif (bio->bi_status)\n\t\tset_btree_node_io_error(b);\n\n\tbch_bbio_free(bio, b->c);\n\n\tif (btree_node_io_error(b))\n\t\tgoto err;\n\n\tbch_btree_node_read_done(b);\n\tbch_time_stats_update(&b->c->btree_read_time, start_time);\n\n\treturn;\nerr:\n\tbch_cache_set_error(b->c, \"io error reading bucket %zu\",\n\t\t\t    PTR_BUCKET_NR(b->c, &b->key, 0));\n}\n\nstatic void btree_complete_write(struct btree *b, struct btree_write *w)\n{\n\tif (w->prio_blocked &&\n\t    !atomic_sub_return(w->prio_blocked, &b->c->prio_blocked))\n\t\twake_up_allocators(b->c);\n\n\tif (w->journal) {\n\t\tatomic_dec_bug(w->journal);\n\t\t__closure_wake_up(&b->c->journal.wait);\n\t}\n\n\tw->prio_blocked\t= 0;\n\tw->journal\t= NULL;\n}\n\nstatic CLOSURE_CALLBACK(btree_node_write_unlock)\n{\n\tclosure_type(b, struct btree, io);\n\n\tup(&b->io_mutex);\n}\n\nstatic CLOSURE_CALLBACK(__btree_node_write_done)\n{\n\tclosure_type(b, struct btree, io);\n\tstruct btree_write *w = btree_prev_write(b);\n\n\tbch_bbio_free(b->bio, b->c);\n\tb->bio = NULL;\n\tbtree_complete_write(b, w);\n\n\tif (btree_node_dirty(b))\n\t\tqueue_delayed_work(btree_io_wq, &b->work, 30 * HZ);\n\n\tclosure_return_with_destructor(cl, btree_node_write_unlock);\n}\n\nstatic CLOSURE_CALLBACK(btree_node_write_done)\n{\n\tclosure_type(b, struct btree, io);\n\n\tbio_free_pages(b->bio);\n\t__btree_node_write_done(&cl->work);\n}\n\nstatic void btree_node_write_endio(struct bio *bio)\n{\n\tstruct closure *cl = bio->bi_private;\n\tstruct btree *b = container_of(cl, struct btree, io);\n\n\tif (bio->bi_status)\n\t\tset_btree_node_io_error(b);\n\n\tbch_bbio_count_io_errors(b->c, bio, bio->bi_status, \"writing btree\");\n\tclosure_put(cl);\n}\n\nstatic void do_btree_node_write(struct btree *b)\n{\n\tstruct closure *cl = &b->io;\n\tstruct bset *i = btree_bset_last(b);\n\tBKEY_PADDED(key) k;\n\n\ti->version\t= BCACHE_BSET_VERSION;\n\ti->csum\t\t= btree_csum_set(b, i);\n\n\tBUG_ON(b->bio);\n\tb->bio = bch_bbio_alloc(b->c);\n\n\tb->bio->bi_end_io\t= btree_node_write_endio;\n\tb->bio->bi_private\t= cl;\n\tb->bio->bi_iter.bi_size\t= roundup(set_bytes(i), block_bytes(b->c->cache));\n\tb->bio->bi_opf\t\t= REQ_OP_WRITE | REQ_META | REQ_FUA;\n\tbch_bio_map(b->bio, i);\n\n\t/*\n\t * If we're appending to a leaf node, we don't technically need FUA -\n\t * this write just needs to be persisted before the next journal write,\n\t * which will be marked FLUSH|FUA.\n\t *\n\t * Similarly if we're writing a new btree root - the pointer is going to\n\t * be in the next journal entry.\n\t *\n\t * But if we're writing a new btree node (that isn't a root) or\n\t * appending to a non leaf btree node, we need either FUA or a flush\n\t * when we write the parent with the new pointer. FUA is cheaper than a\n\t * flush, and writes appending to leaf nodes aren't blocking anything so\n\t * just make all btree node writes FUA to keep things sane.\n\t */\n\n\tbkey_copy(&k.key, &b->key);\n\tSET_PTR_OFFSET(&k.key, 0, PTR_OFFSET(&k.key, 0) +\n\t\t       bset_sector_offset(&b->keys, i));\n\n\tif (!bch_bio_alloc_pages(b->bio, GFP_NOWAIT)) {\n\t\tstruct bio_vec *bv;\n\t\tvoid *addr = (void *) ((unsigned long) i & ~(PAGE_SIZE - 1));\n\t\tstruct bvec_iter_all iter_all;\n\n\t\tbio_for_each_segment_all(bv, b->bio, iter_all) {\n\t\t\tmemcpy(page_address(bv->bv_page), addr, PAGE_SIZE);\n\t\t\taddr += PAGE_SIZE;\n\t\t}\n\n\t\tbch_submit_bbio(b->bio, b->c, &k.key, 0);\n\n\t\tcontinue_at(cl, btree_node_write_done, NULL);\n\t} else {\n\t\t/*\n\t\t * No problem for multipage bvec since the bio is\n\t\t * just allocated\n\t\t */\n\t\tb->bio->bi_vcnt = 0;\n\t\tbch_bio_map(b->bio, i);\n\n\t\tbch_submit_bbio(b->bio, b->c, &k.key, 0);\n\n\t\tclosure_sync(cl);\n\t\tcontinue_at_nobarrier(cl, __btree_node_write_done, NULL);\n\t}\n\n... [Diff truncated. Dropped 2031 lines] ...\n\n\tunsigned long seq = b->seq;\n\tstruct keylist insert;\n\tbool upgrade = op->lock == -1;\n\n\tbch_keylist_init(&insert);\n\n\tif (upgrade) {\n\t\trw_unlock(false, b);\n\t\trw_lock(true, b, b->level);\n\n\t\tif (b->key.ptr[0] != btree_ptr ||\n\t\t    b->seq != seq + 1) {\n\t\t\top->lock = b->level;\n\t\t\tgoto out;\n\t\t}\n\t}\n\n\tSET_KEY_PTRS(check_key, 1);\n\tget_random_bytes(&check_key->ptr[0], sizeof(uint64_t));\n\n\tSET_PTR_DEV(check_key, 0, PTR_CHECK_DEV);\n\n\tbch_keylist_add(&insert, check_key);\n\n\tret = bch_btree_insert_node(b, op, &insert, NULL, NULL);\n\n\tBUG_ON(!ret && !bch_keylist_empty(&insert));\nout:\n\tif (upgrade)\n\t\tdowngrade_write(&b->lock);\n\treturn ret;\n}\n\nstruct btree_insert_op {\n\tstruct btree_op\top;\n\tstruct keylist\t*keys;\n\tatomic_t\t*journal_ref;\n\tstruct bkey\t*replace_key;\n};\n\nstatic int btree_insert_fn(struct btree_op *b_op, struct btree *b)\n{\n\tstruct btree_insert_op *op = container_of(b_op,\n\t\t\t\t\tstruct btree_insert_op, op);\n\n\tint ret = bch_btree_insert_node(b, &op->op, op->keys,\n\t\t\t\t\top->journal_ref, op->replace_key);\n\tif (ret && !bch_keylist_empty(op->keys))\n\t\treturn ret;\n\telse\n\t\treturn MAP_DONE;\n}\n\nint bch_btree_insert(struct cache_set *c, struct keylist *keys,\n\t\t     atomic_t *journal_ref, struct bkey *replace_key)\n{\n\tstruct btree_insert_op op;\n\tint ret = 0;\n\n\tBUG_ON(current->bio_list);\n\tBUG_ON(bch_keylist_empty(keys));\n\n\tbch_btree_op_init(&op.op, 0);\n\top.keys\t\t= keys;\n\top.journal_ref\t= journal_ref;\n\top.replace_key\t= replace_key;\n\n\twhile (!ret && !bch_keylist_empty(keys)) {\n\t\top.op.lock = 0;\n\t\tret = bch_btree_map_leaf_nodes(&op.op, c,\n\t\t\t\t\t       &START_KEY(keys->keys),\n\t\t\t\t\t       btree_insert_fn);\n\t}\n\n\tif (ret) {\n\t\tstruct bkey *k;\n\n\t\tpr_err(\"error %i\\n\", ret);\n\n\t\twhile ((k = bch_keylist_pop(keys)))\n\t\t\tbkey_put(c, k);\n\t} else if (op.op.insert_collision)\n\t\tret = -ESRCH;\n\n\treturn ret;\n}\n\nvoid bch_btree_set_root(struct btree *b)\n{\n\tunsigned int i;\n\tstruct closure cl;\n\n\tclosure_init_stack(&cl);\n\n\ttrace_bcache_btree_set_root(b);\n\n\tBUG_ON(!b->written);\n\n\tfor (i = 0; i < KEY_PTRS(&b->key); i++)\n\t\tBUG_ON(PTR_BUCKET(b->c, &b->key, i)->prio != BTREE_PRIO);\n\n\tmutex_lock(&b->c->bucket_lock);\n\tlist_del_init(&b->list);\n\tmutex_unlock(&b->c->bucket_lock);\n\n\tb->c->root = b;\n\n\tbch_journal_meta(b->c, &cl);\n\tclosure_sync(&cl);\n}\n\n/* Map across nodes or keys */\n\nstatic int bch_btree_map_nodes_recurse(struct btree *b, struct btree_op *op,